const express = require('express');
const router = express.Router();
const Autumn = require('autumn-js');

// Initialize autumn. The exact initialization depends on the SDK version,
// but passing the secret key is standard.
const autumn = new Autumn(process.env.AUTUMN_SECRET_KEY);

router.post('/preview-upgrade', async (req, res) => {
  const { customerId, targetPlanId } = req.body;
  if (!customerId || !targetPlanId) {
    return res.status(400).json({ error: 'customerId and targetPlanId are required' });
  }

  try {
    const preview = await autumn.billing.previewAttach({
      customerId,
      productId: targetPlanId
    });
    return res.status(200).json(preview);
  } catch (err) {
    return res.status(502).json({ error: 'Billing service unavailable', details: err.message });
  }
});

router.post('/confirm-upgrade', async (req, res) => {
  const { customerId, targetPlanId, confirmed } = req.body;
  if (customerId === undefined || targetPlanId === undefined || confirmed === undefined) {
    return res.status(400).json({ error: 'customerId, targetPlanId, and confirmed are required' });
  }

  if (confirmed === false) {
    return res.status(200).json({ status: 'cancelled' });
  }

  try {
    await autumn.attach({ customerId, productId: targetPlanId });
    return res.status(200).json({ status: 'upgraded', customerId, planId: targetPlanId });
  } catch (err) {
    return res.status(502).json({ error: 'Billing service unavailable', details: err.message });
  }
});

router.post('/batch-check', async (req, res) => {
  const { customerIds, featureId } = req.body;
  if (!customerIds || !Array.isArray(customerIds) || !featureId) {
    return res.status(400).json({ error: 'customerIds array and featureId are required' });
  }

  try {
    const results = await Promise.all(
      customerIds.map(async (customerId) => {
        const result = await autumn.customers.check({ customerId, featureId });
        return { customerId, allowed: result.allowed };
      })
    );
    return res.status(200).json({ results });
  } catch (err) {
    return res.status(502).json({ error: 'Billing service unavailable', details: err.message });
  }
});

module.exports = router;

